codeExample1.code:
const original = { name: 'Dev', stats: { hp: 100 } };

// Shallow copy via Spread
const copy = { ...original };

copy.name = 'Admin'; // Only changes copy
copy.stats.hp = 50;  // CHANGES BOTH (Nested object is still a shared reference)

console.log(original.name);    // 'Dev'
console.log(original.stats.hp); // 50 (Surprise!)

// Deep copy (The Fix)
const deepCopy = structuredClone(original);
deepCopy.stats.hp = 0; // Only changes deepCopy

codeExample2.code:
const discountType = 'BLACK_FRIDAY';

const product = {
  id: 'SKU-01',
  price: 500,
  [discountType]: 0.20, // Computed key

  calculatePrice() {
    const discount = this[discountType] || 0;
    return this.price * (1 - discount);
  }
};

// Extracting data dynamically
const metadata = Object.entries(product);
metadata.forEach(([key, value]) => {
  if (typeof value !== 'function') {
    console.log(`${key}: ${value}`);
  }
});

console.log('Final Price:', product.calculatePrice());

